<template>
    <nav class="qg-section-nav" aria-label="side navigation" role="navigation">
        <h2><a href="/environment/land/state/application/forms">State land application forms</a></h2>
        <div class="qg-spinner-land-form align-center" role="status" v-if="getPanelList.length === 0">
            <div class="spinner-border"></div>
            <span class="qg-spinner-label">Loading...</span>
        </div>
        <ul aria-label="section navigation" v-else>
            <li>
                <a href="/environment/land/state/application/forms/services/forms/application-for-conversion-of-a-lease">Application for conversion of a lease</a>
            </li>
            <li>
                <ol class="lb guide-sub-nav" aria-label="section navigation">
                    <li
                        v-for="(panel, index) in getPanelList"
                        @click="changePanelHandler(panel, index)"
                        :key="panel.key"
                        href="#"
                        class="guide-sub-nav-item"
                    >
                        <a href="#"
                           :class="[panel.isActive ? 'active' : '', panel.isDisabled ? 'disabled' : '']"
                        >
                            <span class="page-number" v-text="index+1"></span>
                            {{ panel.title }}
                        </a>
                    </li>
                </ol>
            </li>
        </ul>
    </nav>
</template>

<script>

import {mapGetters, mapActions} from 'vuex'

export default {
    name: 'LeftSideBar',
    computed: {
        ...mapGetters([
            'getPanelList'
        ])
    },
    methods: {
        /**
         * Change the navigation on left sidebar.
         */
        changePanelHandler(panel, index) {
            if (panel.isDisabled) {
                return
            }

            this.updateCurrentPageIndex(index)
        },
        ...mapActions([
            'updateCurrentPageIndex'
        ]),
    }
}
</script>

