<script>
import LeftSideBar from './components/LeftSideBar.vue'
import FormWrapper from './components/FormWrapper.vue'
import RightSideBar from './components/RightSideBar.vue'

export default {
    name: 'App',
    components: {
        LeftSideBar,
        FormWrapper,
        RightSideBar
    },
    data() {
        return {
            projectUrl: process.env.VUE_APP_PROJECT_URL,
            wizardUrl: process.env.VUE_APP_WIZARD_URL,
            savedApplicationPage: process.env.VUE_APP_SAVED_APPLICATION_PAGE,
            thankYouPage: process.env.VUE_APP_THANK_YOU_PAGE,
            userId: process.env.VUE_APP_USER_ID,
            submissionId: '',
        }
    },
    beforeMount() {
        let queryString = window.location.search;
        let urlParams = new URLSearchParams(queryString);
        let submissionId = urlParams.get('submissionId')
        if (submissionId) {
            this.wizardUrl = this.wizardUrl + '/submission/' + submissionId
            this.submissionId = submissionId
        }
    }
}
</script>

